mapper.select:
SELECT s.stock_amount
FROM stock s
JOIN item i ON i.item_id = s.item_id
    AND i.store_id = #{storeId}
    AND i.is_active = b'1'
WHERE s.item_id = #{itemId}

mapper.update:
UPDATE stock s
JOIN item i ON i.item_id = s.item_id
SET s.stock_amount = s.stock_amount - #{amount},
    s.updated_at   = CURRENT_TIMESTAMP
WHERE s.item_id = #{itemId}
  AND i.store_id = #{storeId}
  AND s.stock_amount >= #{amount}
  AND i.is_active = b'1'
